  "inlineSchema": "// PokeHub schema — see /.context/design.md for design decisions.\n\ngenerator client {\n  provider        = \"prisma-client-js\"\n  output          = \"../generated/prisma\"\n  previewFeatures = [\"postgresqlExtensions\"]\n}\n\ndatasource db {\n  provider   = \"postgresql\"\n  url        = env(\"DATABASE_URL\")\n  directUrl  = env(\"DIRECT_URL\")\n  extensions = [pg_trgm]\n}\n\n// =====================================================================\n// Auth (NextAuth + Prisma adapter)\n// =====================================================================\n\nenum UserRole {\n  USER\n  ADMIN\n}\n\nmodel User {\n  id             String    @id @default(cuid())\n  name           String?\n  email          String?   @unique\n  emailVerified  DateTime?\n  image          String?\n  role           UserRole  @default(USER)\n  password       String?\n  marketingOptIn Boolean   @default(false)\n  accounts       Account[]\n  sessions       Session[]\n  orders         Order[]\n}\n\nmodel Account {\n  id                       String  @id @default(cuid())\n  userId                   String\n  type                     String\n  provider                 String\n  providerAccountId        String\n  refresh_token            String?\n  access_token             String?\n  expires_at               Int?\n  token_type               String?\n  scope                    String?\n  id_token                 String?\n  session_state            String?\n  user                     User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  refresh_token_expires_in Int?\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\n// =====================================================================\n// Catalog (seeded from pokemontcg.io)\n// =====================================================================\n\nmodel Era {\n  id   String @id // e.g. \"SV\"\n  name String @unique // e.g. \"Scarlet & Violet\"\n\n  sets CardSet[]\n}\n\nmodel CardSet {\n  id    String @id // e.g. \"swsh3\"\n  name  String @unique\n  eraId String\n  era   Era    @relation(fields: [eraId], references: [id])\n\n  cards          Card[]\n  sealedProducts SealedProductCardSet[]\n}\n\nmodel Artist {\n  id    String @id @default(uuid())\n  name  String\n  cards Card[]\n}\n\nenum FoilType {\n  NON_HOLO\n  HOLO\n  GALAXY_HOLO\n  COSMOS_HOLO\n  LINE_HOLO\n  REVERSE_HOLO\n  STAMPED_REVERSE_HOLO\n  ENERGY_SYMBOL_REVERSE_HOLO\n  MASTER_BALL_REVERSE_HOLO\n  POKEBALL_REVERSE_HOLO\n  SET_LOGO_REVERSE_HOLO\n  COSMOS_REVERSE_HOLO\n  FULL_ART\n  TEXTURED_FULL_ART\n  ALTERNATE_ART\n  SPECIAL_ILLUSTRATION_RARE\n  RAINBOW_RARE\n  GOLD_SECRET_RARE\n  SHINY_HOLO\n  BABY_SHINY\n  SHINY_FULL_ART\n  RADIANT\n  EX_HOLO\n  GX_FULL_ART\n  V_HOLO\n  VMAX_TEXTURED\n  VSTAR_HOLO\n  PRE_RELEASE_STAMPED\n  LEAGUE_PROMO_STAMPED\n  STAFF_PROMO_HOLO\n  CRACKED_ICE_HOLO\n  MCDONALDS_HOLO\n  TOYSRUS_HOLO\n  KFC_HOLO\n  ETCHED_FULL_ART\n  OTHER\n}\n\nmodel Card {\n  id       String    @id // e.g. \"swsh3-136\"\n  name     String\n  setId    String\n  set      CardSet   @relation(fields: [setId], references: [id])\n  number   String\n  rarity   String?\n  artistId String\n  artist   Artist    @relation(fields: [artistId], references: [id])\n  foilType FoilType\n  imageUrl String?\n  types    String[] // e.g. [\"Fire\", \"Water\"]\n  products Product[]\n\n  @@index([name])\n  @@index([setId])\n}\n\n// =====================================================================\n// Inventory — single Product table with discriminator\n// =====================================================================\n\nenum ProductType {\n  RAW\n  GRADED\n  SEALED\n}\n\nenum Language {\n  ENGLISH\n  JAPANESE\n}\n\nenum CardCondition {\n  NM\n  LP\n  MP\n  HP\n  DMG\n}\n\nenum GradingCompany {\n  PSA\n  BGS\n  CGC\n  SGC\n  ACE\n  OTHER\n}\n\nenum SealedType {\n  BOOSTER_PACK\n  BOOSTER_BOX\n  MINI_BOOSTER_BOX\n  ELITE_TRAINER_BOX\n  ETB_PLUS\n  COLLECTION_BOX\n  PREMIUM_COLLECTION_BOX\n  TIN\n  MINI_TIN\n  LUNCHBOX_TIN\n  BLISTER_PACK\n  CHECKLANE_BLISTER\n  TRIPLE_BLISTER\n  BUILD_AND_BATTLE_BOX\n  BUILD_AND_BATTLE_STADIUM\n  THEME_DECK\n  STARTER_DECK\n  V_BATTLE_DECK\n  VMAX_BATTLE_BOX\n  VSTAR_PREMIUM_COLLECTION\n  SPECIAL_COLLECTION_BOX\n  POKEBALL_TIN\n  ULTRA_PREMIUM_COLLECTION\n  HOLIDAY_CALENDAR\n  MYSTERY_BOX\n  SLEEVE_BOOSTER_PACK\n  PRE_RELEASE_KIT\n  BOX_SET\n  OTHER\n}\n\n// Discriminated single table. Subtype-specific fields are nullable;\n// Zod refinements at the tRPC boundary enforce per-type required fields.\nmodel Product {\n  id          String      @id @default(uuid())\n  type        ProductType\n  description String?\n  language    Language    @default(ENGLISH)\n  priceCents  Int\n  quantity    Int         @default(0)\n  imageUrl    String? // user-uploaded photo (graded slabs, sealed product)\n  createdAt   DateTime    @default(now())\n  updatedAt   DateTime    @updatedAt\n\n  // RAW + GRADED fields\n  cardId    String?\n  card      Card?          @relation(fields: [cardId], references: [id])\n  condition CardCondition? // RAW only\n\n  // GRADED only\n  gradingCompany GradingCompany?\n  grade          Decimal?        @db.Decimal(3, 1)\n  certNumber     String?         @unique\n  caseCondition  String?\n\n  // SEALED only\n  name        String?\n  sealedType  SealedType?\n  releaseDate DateTime?              @db.Date\n  region      String?\n  sealedSets  SealedProductCardSet[]\n\n  orderItems OrderItem[]\n\n  @@unique([cardId, condition], name: \"uk_raw_card_identity\")\n  @@index([type])\n  @@index([quantity])\n  @@index([cardId])\n}\n\nmodel SealedProductCardSet {\n  productId String\n  cardSetId String\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  cardSet   CardSet @relation(fields: [cardSetId], references: [id])\n\n  @@id([productId, cardSetId])\n}\n\n// =====================================================================\n// Orders\n// =====================================================================\n\nenum OrderStatus {\n  PENDING_PAYMENT\n  PAID\n  FAILED\n  CANCELED\n  EXPIRED\n  FULFILLED\n}\n\nmodel Order {\n  id                    String      @id @default(uuid())\n  orderNumber           String      @unique // e.g. \"PHB-7X4K2M\"\n  userId                String?\n  user                  User?       @relation(fields: [userId], references: [id])\n  email                 String\n  status                OrderStatus @default(PENDING_PAYMENT)\n  stripePaymentIntentId String?     @unique\n  subtotalCents         Int\n  shippingCents         Int\n  taxCents              Int         @default(0)\n  totalCents            Int\n  shippingAddressJson   Json\n  trackingNumber        String?\n  createdAt             DateTime    @default(now())\n  updatedAt             DateTime    @updatedAt\n  paidAt                DateTime?\n  fulfilledAt           DateTime?\n  items                 OrderItem[]\n\n  @@index([status])\n  @@index([email])\n  @@index([createdAt])\n}\n\nmodel OrderItem {\n  id                   String  @id @default(uuid())\n  orderId              String\n  order                Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  productId            String\n  product              Product @relation(fields: [productId], references: [id])\n  productSnapshotJson  Json // name, type, condition/grade, image, etc. at purchase time\n  priceAtPurchaseCents Int\n  quantity             Int\n\n  @@index([orderId])\n}\n\n// =====================================================================\n// Webhook idempotency\n// =====================================================================\n\nmodel ProcessedWebhook {\n  stripeEventId String   @id\n  processedAt   DateTime @default(now())\n}\n",
